    value: Option<String>,
    default: Option<String>,
) -> Result<Option<String>> {
    match value {
        Some(value) => Ok((!value.trim().is_empty()).then_some(value)),
        None if interactive => {
            let value = prompt_line_allow_empty(output, label, default)?;
