                        log.duration_ms,
                        log.usage.input_tokens.unwrap_or_default(),
                        log.usage.output_tokens.unwrap_or_default(),
                        log.usage.total_tokens.unwrap_or_default()
                    )?;
                }
            }
            LogCommand::Summary { limit } => {
                let logs = paths.storage_handle()?.list_request_logs(limit)?;
                if logs.is_empty() {
