                        output,
                        "No logs yet. Start Gunmetal with `gunmetal start`, then make one request."
                    )?;
                } else {
                    write_log_summary(&mut output, &logs)?;
                }
            }
        },
        Command::Tui => {}
    }

    Ok(())
}

