  /* Scale in — CTAs, cards */
  .animate-scale {
    animation: scaleIn var(--duration-normal) var(--ease-out) both;
  }

  /* Reveal on scroll */
  .reveal {
    opacity: 0;
    transform: translateY(20px);
  }

  .reveal.is-visible {
    opacity: 1;
    transform: translateY(0);
    transition:
      opacity var(--duration-slow) var(--ease-out),
      transform var(--duration-slow) var(--ease-out);
