    line-height: 1.50;
    letter-spacing: -0.02em;
  }
}

/* ============================================
   ANIMATION UTILITIES
   ============================================ */

@layer utilities {
  /* Fade in — opacity only */
  .animate-in {
    animation: fadeIn var(--duration-normal) var(--ease-out) both;
  }

  /* Fade in up — subtle Y shift */
  .animate-up {
    animation: fadeUp var(--duration-normal) var(--ease-out) both;
  }

  /* Scale in — CTAs, cards */
  .animate-scale {
    animation: scaleIn var(--duration-normal) var(--ease-out) both;
  }

  /* Reveal on scroll */
  .reveal {
    opacity: 0;
    transform: translateY(20px);
  }

  .reveal.is-visible {
    opacity: 1;
    transform: translateY(0);
    transition:
      opacity var(--duration-slow) var(--ease-out),
      transform var(--duration-slow) var(--ease-out);
  }

  /* Stagger delays */
  .delay-100 { animation-delay: 100ms; }
  .delay-200 { animation-delay: 200ms; }
  .delay-300 { animation-delay: 300ms; }
  .delay-400 { animation-delay: 400ms; }
  .delay-500 { animation-delay: 500ms; }
  .delay-600 { animation-delay: 600ms; }
  .delay-800 { animation-delay: 800ms; }
  .delay-1000 { animation-delay: 1000ms; }
  .delay-1400 { animation-delay: 1400ms; }
  .delay-1800 { animation-delay: 1800ms; }

  /* Initially hidden */
  .is-ready {
    opacity: 0;
  }
}

/* ============================================
   KEYFRAMES
   ============================================ */

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes scaleIn {
  from { opacity: 0; transform: scale(0.96); }
  to { opacity: 1; transform: scale(1); }
}

@keyframes typewriter {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

@keyframes pulse-ring {
  0% { transform: scale(1); opacity: 0.4; }
  100% { transform: scale(1.5); opacity: 0; }
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

@keyframes pkg-scroll {
  0%, 30% { transform: translateY(0); }
  33.33%, 63.33% { transform: translateY(-1.4em); }
  66.66%, 96.66% { transform: translateY(-2.8em); }
  100% { transform: translateY(-4.2em); }
}

@layer utilities {
  .animate-pkg-scroll {
    animation: pkg-scroll 7.5s cubic-bezier(0.87, 0, 0.13, 1) infinite;
  }
}

/* ============================================
   COMPONENT UTILITIES
   ============================================ */

/* Blueprint grid — barely visible warm lines */
.grid-bg {
  background-image:
    linear-gradient(var(--grid-color) 1px, transparent 1px),
    linear-gradient(90deg, var(--grid-color) 1px, transparent 1px);
  background-size: var(--grid-size) var(--grid-size);
}

/* Radial glow — warm, very subtle */
.glow-warm {
  background: radial-gradient(
    ellipse 80% 50% at 50% 120%,
    rgba(250, 249, 246, 0.04) 0%,
    transparent 70%
  );
}

/* Glass navbar on scroll */
.glass {
  background: rgba(14, 14, 13, 0.80);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
}

/* Card — semi-transparent border containment */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
}

.card:hover {
  border-color: var(--border-strong);
}

/* Terminal window */
.terminal {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.terminal-header {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
}

.terminal-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
}

.terminal-body {
  padding: 20px 24px;
}

/* Pill button */
.btn-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 20px;
  background: var(--btn-bg);
  color: var(--btn-text);
  border: 1px solid var(--btn-border);
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);
  font-size: 0.9375rem;
  font-weight: 400;
  letter-spacing: 0;
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.btn-pill:hover {
  background: var(--btn-hover-bg);
  color: var(--btn-hover-text);
}

/* CTA pill — light, on dark */
.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  background: var(--cta-bg);
  color: var(--cta-text);
  border: 1px solid transparent;
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);
  font-size: 0.9375rem;
  font-weight: 400;
  letter-spacing: 0;
  cursor: pointer;
  transition: all var(--duration-fast) var(--ease-out);
  white-space: nowrap;
}

.btn-cta:hover {
  background: var(--cta-hover-bg);
}

/* Ghost pill — border only */
.btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  background: transparent;
  color: var(--text-secondary);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-pill);
  font-family: var(--font-matter);

