pub async fn daemon_status(paths: &AppPaths, host: IpAddr, port: u16) -> Result<ServiceStatus> {
    let url = format!("http://{host}:{port}");
    let health_url = format!("{url}/health");
    let pid = managed_daemon_pid(paths)?;
    match reqwest::get(&health_url).await {
        Ok(response) => {
            let health = response.text().await.ok();
            let home = daemon_home(&url).await;
            Ok(ServiceStatus {
                state: "running".to_owned(),
                running: true,
                pid,
                url,
                health,
                home,
                note: None,
            })
        }
        Err(_) => {
            if let Some(pid) = pid {
                if process_exists(pid) {
                    return Ok(ServiceStatus {
                        state: "starting".to_owned(),
                        running: false,
                        pid: Some(pid),
                        url,
                        health: None,
                        home: None,
                        note: Some("Gunmetal is still starting.".to_owned()),
                    });
                }
                let _ = fs::remove_file(paths.daemon_pid_file());
                return Ok(ServiceStatus {
                    state: "stopped".to_owned(),
                    running: false,
                    pid: None,
                    url,
                    health: None,
                    home: None,
                    note: Some("Removed stale daemon state.".to_owned()),
                });
            }
            Ok(ServiceStatus {
                state: "stopped".to_owned(),
                running: false,
                pid: None,
                url,
                health: None,
                home: None,
                note: None,
            .status()?;
        if !status.success() {
            anyhow::bail!("failed to stop daemon pid {pid}");
        }
    }

    Ok(())
}

